import{_ as t,o as s,c as i,ag as e}from"./chunks/framework.uOkKsJ4G.js";const k=JSON.parse('{"title":"批量处理","description":"Narrafiilm 批量处理功能说明（v3.4.0 已整合至单次工作流）。","frontmatter":{"title":"批量处理","description":"Narrafiilm 批量处理功能说明（v3.4.0 已整合至单次工作流）。"},"headers":[],"relativePath":"guide/batch-processing.md","filePath":"guide/batch-processing.md","lastUpdated":1775974638000}'),n={name:"guide/batch-processing.md"};function l(d,a,r,h,o,p){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="批量处理" tabindex="-1">批量处理 <a class="header-anchor" href="#批量处理" aria-label="Permalink to &quot;批量处理&quot;">​</a></h1><blockquote><p>⚠️ <strong>版本说明</strong>：独立批量处理面板已于 <strong>v3.4.0</strong> 整合至单次工作流。通过创建多个项目并逐个处理，可实现等效的批量操作。详情见下方说明。</p></blockquote><hr><h2 id="v3-4-0-变更说明" tabindex="-1">v3.4.0 变更说明 <a class="header-anchor" href="#v3-4-0-变更说明" aria-label="Permalink to &quot;v3.4.0 变更说明&quot;">​</a></h2><p>v3.4.0 品牌聚焦重构中，移除了独立的批量处理界面。原批量处理能力通过以下方式保留：</p><p><strong>等效替代方案</strong>：创建多个 Narrafiilm 项目，逐个处理视频。每个项目独立运行，互不干扰，适合多视频顺序处理场景。</p><blockquote><p>💡 <strong>未来版本</strong>计划将批量队列功能重新引入，作为单次工作流的增强功能。如有此需求，请在 <a href="https://github.com/Agions/Narrafiilm/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> 反馈。</p></blockquote><hr><h2 id="多视频处理建议工作流" tabindex="-1">多视频处理建议工作流 <a class="header-anchor" href="#多视频处理建议工作流" aria-label="Permalink to &quot;多视频处理建议工作流&quot;">​</a></h2><h3 id="方式一-逐个项目处理" tabindex="-1">方式一：逐个项目处理 <a class="header-anchor" href="#方式一-逐个项目处理" aria-label="Permalink to &quot;方式一：逐个项目处理&quot;">​</a></h3><ol><li>为每个视频创建独立项目（<strong>项目 → 新建项目</strong>）</li><li>逐个导入视频并生成解说</li><li>统一设置输出目录，按项目名自动分类</li></ol><p>输出目录结构示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Videos/Narrafiilm/</span></span>
<span class="line"><span>├── keynote_presentation/</span></span>
<span class="line"><span>│   └── final.mp4</span></span>
<span class="line"><span>├── conference_session2/</span></span>
<span class="line"><span>│   └── final.mp4</span></span>
<span class="line"><span>└── travel_vlog_ep3/</span></span>
<span class="line"><span>    └── final.mp4</span></span></code></pre></div><h3 id="方式二-ffmpeg-批量合并-如需合并多个成品" tabindex="-1">方式二：FFmpeg 批量合并（如需合并多个成品） <a class="header-anchor" href="#方式二-ffmpeg-批量合并-如需合并多个成品" aria-label="Permalink to &quot;方式二：FFmpeg 批量合并（如需合并多个成品）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 合并同目录所有 MP4（需安装 FFmpeg）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output_dir</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> concat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -safe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> *.mp4; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;file &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&quot;; done)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merged.mp4</span></span></code></pre></div><hr><h2 id="输出管理" tabindex="-1">输出管理 <a class="header-anchor" href="#输出管理" aria-label="Permalink to &quot;输出管理&quot;">​</a></h2><h3 id="自动命名规则" tabindex="-1">自动命名规则 <a class="header-anchor" href="#自动命名规则" aria-label="Permalink to &quot;自动命名规则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变量</th><th>效果</th></tr></thead><tbody><tr><td><code>{filename}</code></td><td>原始文件名（无扩展名）</td></tr><tr><td><code>{date}</code></td><td>处理日期（YYYY-MM-DD）</td></tr><tr><td><code>{time}</code></td><td>处理时间（HH-MM-SS）</td></tr><tr><td><code>{mode}</code></td><td>情感风格</td></tr></tbody></table><h3 id="批量导出配置" tabindex="-1">批量导出配置 <a class="header-anchor" href="#批量导出配置" aria-label="Permalink to &quot;批量导出配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td>统一编码</td><td>H.264 / H.265</td></tr><tr><td>统一分辨率</td><td>保持原片 / 1080p / 720p</td></tr><tr><td>统一输出目录</td><td>所有项目输出到同一父目录</td></tr></tbody></table><hr><h2 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to &quot;快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>Windows</th><th>macOS</th></tr></thead><tbody><tr><td>新建项目</td><td><code>Ctrl+N</code></td><td><code>⌘N</code></td></tr><tr><td>打开项目</td><td><code>Ctrl+O</code></td><td><code>⌘O</code></td></tr><tr><td>快速导出</td><td><code>Ctrl+E</code></td><td><code>⌘E</code></td></tr></tbody></table><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./quick-start.html">快速开始</a> — 单视频 5 分钟上手</li><li><a href="./exporting.html">导出格式</a> — 详细导出参数配置</li><li><a href="./troubleshooting.html">疑难排查</a> — 处理过程中的问题解决</li></ul>`,27)])])}const g=t(n,[["render",l]]);export{k as __pageData,g as default};
